import React, { Component } from 'react';

class Form extends Component {
    render() {
        return (
            
            <form className="ContactForm">
                    <p>Name:</p>
                    <input type="text" name="Name" />
                    <br /><p>Email:</p>
                    <input type="text" name="Email" />
                    <br /><p>Messenges:</p>
                    <textarea rows={4} defaultValue={""} />
            </form>
        );
    }
}

export default Form;
